  ('disabled-6f0ba476-moex-00451', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '受輔助宣告之人，受贈房屋一棟時，其效力如何？', '["有效", "效力未定", "得撤銷", "無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00452', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於消滅時效之敘述，何者正確？', '["消滅時效之起算點，均自請求權可行使時起算", "時效完成後，債務人得拒絕給付", "以普通抵押權擔保之請求權，因時效消滅後，債權人不得就其抵押 物取償", "主權利因時效消滅者，其效力不及於從權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00453', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲於路上見乙搶劫丙之背包，見義勇為，上前勒住乙之頸脖，至乙斷 氣方始放手。下列敘述，何者正確？', '["此為權利行使", "此為自助行為", "此為過當防衛", "此為緊急避難"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00454', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '法律之適用須透過解釋，下列關於民法解釋及補充之方法，何者錯誤？', '["各種解釋方法間不具有固定不變之位階關係，不僅限於一種解釋方法", "公開漏洞應透過類推適用進行填補", "體系解釋屬於民法解釋方法之一", "擴張解釋，係以法律文義外之最大可能解釋範圍，為其解釋對象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00455', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '倘若於文件中關於一定數量同時以文字、號碼為一次或數次表示，如 不能決定何者為當事人之原意，下列敘述，何者錯誤？', '["倘若該數量係以文字為數次之表示而其表示不同時，以文字最低 額為準", "倘若該數量係以號碼為數次之表示而其表示不同時，以號碼最低 額為準", "倘若該數量以文字及號碼各表示一次，而彼此不一致時，以文字 為準", "倘若當事人同時以號碼及文字重複為數次之表示而其表示彼此不 相同時，實務上皆以總體最低額為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00456', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者非屬除斥期間之適用客體？', '["表意人因被詐欺為意思表示，而行使撤銷該意思表示之權利", "承租人就未定期之租賃契約，行使終止契約之權利", "買受人因買賣之種類物有瑕疵，而行使另行交付無瑕疵之物之權利", "買受人因買賣標的物有瑕疵，而行使解除契約之權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00457', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於違約金之敘述，何者錯誤？', '["違約金為不要物契約", "違約金的種類，可分為損害賠償總額預定性違約金與懲罰性違約金", "當事人得約定債務人於債務不履行時，應支付違約金；違約金，除 當事人另有訂定外，推定為因不履行而生損害之賠償總額", "約定之違約金額過高者，法院得減至相當之數額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00458', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '民法第191 條之 1 所規定之商品製造人責任，有關侵權行為成立要件 之推定，下列何者不屬之？', '["商品設計有欠缺", "商品設計欠缺與損害間有因果關係", "損害之存在", "行為人之過失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00459', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲基於使用借貸契約，對乙負擔返還Ａ畫之義務，並約定甲應將Ａ畫 送至乙之住處。甲依約將Ａ畫送至乙處時，乙因外出而中暑暈倒，無 法即時回來。下列敘述，何者正確？', '["此為不可歸責於乙之事由，不構成受領遲延", "乙之行為構成受領遲延，債務人甲對於Ａ畫之交付，僅就故意或重 大過失負其責任", "甲得拋棄對Ａ畫之占有", "乙之行為同時構成給付不能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00460', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於債務承擔之敘述，何者錯誤？', '["債權人拒絕承認債務人與第三人所訂立之債務承擔契約時，該債務 承擔契約無效", "債務人因其法律關係，所得對抗債權人之事由，承擔人亦得以之對 抗債權人", "從屬於債權之權利，若非由第三人就債權所為之擔保者，原則上不 因債務之承擔而妨礙其存在", "債務人對於債權人有債權者，債務承擔人不得以債務人之債權，與 債權人主張抵銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": "27c6e51c4193", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
